import React, { useEffect, useState } from "react";
import api from "../api";
import FoodCard from "../components/FoodCard";

export default function FoodMenu() {
  const [foods, setFoods] = useState([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchFoods = async () => {
      try {
        const res = await api.get("/foods");
        setFoods(res.data);
      } catch (error) {
        console.error("Error fetching foods:", error);
        alert("Something went wrong while fetching the food list.");
      } finally {
        setLoading(false);
      }
    };
    fetchFoods();
  }, []);

  const filteredFoods = foods.filter((food) =>
    food.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const placeOrder = async (foodId) => {
    try {
      await api.post("/orders", { items: [{ food: foodId, quantity: 1 }] });
      alert("Order placed!");
    } catch (error) {
      console.error("Error placing order:", error);
      alert("Failed to place order. Please try again.");
    }
  };

  const addFood = () => {
    // Redirect to an 'Add Food' page
  };

  const setTodayItem = async (foodId) => {
    try {
      await api.post("/set-today-menu", { foodId });
      alert("Food marked for today!");
    } catch (error) {
      console.error("Error marking food for today:", error);
      alert("Failed to update today's menu.");
    }
  };

  return (
    <div className="container mt-5">
      {/* Search Bar */}
      <div className="d-flex justify-content-between mb-4">
        <input
          type="text"
          className="form-control w-50"
          placeholder="Search food..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
        <button className="btn btn-primary" onClick={addFood}>
          Add Food
        </button>
      </div>

      {/* Loading */}
      {loading ? (
        <div>Loading...</div>
      ) : (
        <div className="row">
          {filteredFoods.map((food) => (
            <div key={food._id} className="col-md-4 mb-4">
              <div className="card">
                <FoodCard food={food} onOrder={placeOrder} />
                <div className="card-body">
                  <div className="d-flex justify-content-between">
                    <button
                      className="btn btn-success"
                      onClick={() => setTodayItem(food._id)}
                    >
                      Today Item
                    </button>
                    <button
                      className="btn btn-warning"
                      onClick={() => window.location.href = `/manage/${food._id}`}
                    >
                      Manage
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
